30	+  const parts = /^([0-9]{4})-([0-9]{2})-([0-9]{2})$/.exec(value);
31	+  if (!parts) return false;
32	+
33	+  const year = Number(parts[1]);
34	+  const month = Number(parts[2]);
35	+  const day = Number(parts[3]);
36	+  const date = new Date(Date.UTC(year, month - 1, day));
37	+
38	+  return date.getUTCFullYear() === year
39	+    && date.getUTCMonth() === month - 1
40	+    && date.getUTCDate() === day;
41	+}
