43	+function submittedAtTimestamp(value) {
44	+  if (!isNonEmptyString(value)) return Number.NaN;
45	+
46	+  if (/^[+-]?[0-9]+(?:\.[0-9]+)?$/.test(value)) {
47	+    const timestamp = Number(value);
48	+    return Number.isFinite(timestamp) ? timestamp : Number.NaN;
49	+  }
50	+
51	+  return Date.parse(value);
52	+}
