54	+function validateFulfillWaveInput(input) {
55	+  ensure(input !== null && typeof input === 'object' && !Array.isArray(input),
56	+    'input must be a JSON object');
57	+  ensure(Array.isArray(input.warehouses), 'warehouses must be an array');
58	+  ensure(Array.isArray(input.orders), 'orders must be an array');
59	+
60	+  for (const warehouse of input.warehouses) {
61	+    ensure(warehouse !== null && typeof warehouse === 'object' && !Array.isArray(warehouse),
62	+      'warehouse must be an object');
63	+    ensure(isNonEmptyString(warehouse.id), 'warehouse id must be a non-empty string');
64	+    ensure(typeof warehouse.distance === 'number' && Number.isFinite(warehouse.distance),
65	+      'warehouse distance must be a number');
66	+    ensure(Array.isArray(warehouse.lots), 'warehouse lots must be an array');
67	+
68	+    for (const lot of warehouse.lots) {
69	+      ensure(lot !== null && typeof lot === 'object' && !Array.isArray(lot),
70	+        'lot must be an object');
71	+      ensure(isNonEmptyString(lot.sku), 'lot sku must be a non-empty string');
72	+      ensure(isNonEmptyString(lot.lot), 'lot id must be a non-empty string');
73	+      ensure(isPositiveInteger(lot.qty), 'lot qty must be a positive integer');
74	+      ensure(isValidDate(lot.expires), 'lot expires must be a valid YYYY-MM-DD date');
75	+    }
76	+  }
77	+
78	+  const orderIds = new Set();
79	+  for (const order of input.orders) {
80	+    ensure(order !== null && typeof order === 'object' && !Array.isArray(order),
81	+      'order must be an object');
82	+    ensure(isNonEmptyString(order.id), 'order id must be a non-empty string');
83	+    ensure(!orderIds.has(order.id), 'order ids must be unique');
84	+    orderIds.add(order.id);
85	+    ensure(typeof order.priority === 'number' && Number.isFinite(order.priority),
86	+      'order priority must be a number');
87	+    ensure(Number.isFinite(submittedAtTimestamp(order.submitted_at)),
88	+      'order submitted_at must be an ISO date or timestamp');
89	+    ensure(Array.isArray(order.lines), 'order lines must be an array');
90	+
91	+    for (const line of order.lines) {
92	+      ensure(line !== null && typeof line === 'object' && !Array.isArray(line),
93	+        'order line must be an object');
94	+      ensure(isNonEmptyString(line.sku), 'order line sku must be a non-empty string');
95	+      ensure(isPositiveInteger(line.qty), 'order line qty must be a positive integer');
96	+      ensure(typeof line.single_warehouse === 'boolean',
97	+        'order line single_warehouse must be a boolean');
98	+    }
99	+  }
100	+}
101	+
102	+function parseInputFlag(argv) {
103	+  const index = argv.indexOf('--input');
104	+  const inputPath = argv[index + 1];
105	+  ensure(index !== -1 && isNonEmptyString(inputPath) && !inputPath.startsWith('-'),
106	+    '--input requires a path');
107	+  return inputPath;
108	+}
109	+
110	+function compareWarehouses(left, right) {
111	+  return compareValues(left.distance, right.distance)
112	+    || compareValues(left.id, right.id);
113	+}
114	+
115	+function compareLots(left, right) {
116	+  return compareValues(left.expires, right.expires)
117	+    || compareValues(left.lot, right.lot);
118	+}
119	+
120	+function buildWorkingStock(warehouses) {
121	+  return warehouses.map((warehouse) => ({
122	+    id: warehouse.id,
123	+    distance: warehouse.distance,
124	+    lots: warehouse.lots.map((lot) => ({
125	+      sku: lot.sku,
126	+      lot: lot.lot,
127	+      qty: lot.qty,
128	+      expires: lot.expires,
129	+    })).sort(compareLots),
130	+  })).sort(compareWarehouses);
131	+}
132	+
133	+function drawFromWarehouse(warehouse, sku, qty, allocations, deductions) {
134	+  let remaining = qty;
135	+
136	+  for (const lot of warehouse.lots) {
137	+    if (lot.sku !== sku || lot.qty === 0 || remaining === 0) continue;
138	+
139	+    const drawn = Math.min(lot.qty, remaining);
140	+    lot.qty -= drawn;
141	+    remaining -= drawn;
142	+    allocations.push({ sku, warehouse: warehouse.id, lot: lot.lot, qty: drawn });
143	+    deductions.push({ lot, qty: drawn });
144	+  }
145	+
146	+  return remaining;
147	+}
148	+
149	+function drawLine(stock, line, allocations, deductions) {
150	+  if (line.single_warehouse) {
151	+    for (const warehouse of stock) {
152	+      const available = warehouse.lots.reduce((total, lot) => (
153	+        lot.sku === line.sku ? total + lot.qty : total
154	+      ), 0);
155	+      if (available >= line.qty) {
156	+        return drawFromWarehouse(warehouse, line.sku, line.qty, allocations, deductions) === 0;
157	+      }
158	+    }
159	+    return false;
160	+  }
161	+
162	+  let remaining = line.qty;
163	+  for (const warehouse of stock) {
164	+    remaining = drawFromWarehouse(warehouse, line.sku, remaining, allocations, deductions);
165	+    if (remaining === 0) {
166	+      return true;
167	+    }
168	+  }
169	+
170	+  return false;
171	+}
172	+
173	+function fulfillWave(input) {
174	+  const stock = buildWorkingStock(input.warehouses);
175	+  const accepted = [];
176	+  const rejectedIds = new Set();
177	+  const orders = input.orders.map((order) => ({
178	+    order,
179	+    submittedAt: submittedAtTimestamp(order.submitted_at),
180	+  })).sort((left, right) => (
181	+    compareValues(right.order.priority, left.order.priority)
182	+      || compareValues(left.submittedAt, right.submittedAt)
183	+      || compareValues(left.order.id, right.order.id)
184	+  ));
185	+
186	+  for (const { order } of orders) {
187	+    const allocations = [];
188	+    const deductions = [];
189	+    const fulfilled = order.lines.every((line) => drawLine(stock, line, allocations, deductions));
190	+
191	+    if (fulfilled) {
192	+      accepted.push({ id: order.id, allocations });
193	+      continue;
194	+    }
195	+
196	+    for (const deduction of deductions) {
197	+      deduction.lot.qty += deduction.qty;
198	+    }
199	+    rejectedIds.add(order.id);
200	+  }
201	+
202	+  const rejected = input.orders
203	+    .filter((order) => rejectedIds.has(order.id))
204	+    .map((order) => ({ id: order.id, reason: 'insufficient_stock' }));
205	+  const remaining = stock.flatMap((warehouse) => warehouse.lots
206	+    .filter((lot) => lot.qty > 0)
207	+    .map((lot) => ({
208	+      warehouse: warehouse.id,
209	+      sku: lot.sku,
210	+      lot: lot.lot,
211	+      qty: lot.qty,
212	+      expires: lot.expires,
213	+    }))).sort((left, right) => (
214	+    compareValues(left.warehouse, right.warehouse)
215	+      || compareValues(left.sku, right.sku)
216	+      || compareValues(left.expires, right.expires)
217	+      || compareValues(left.lot, right.lot)
218	+  ));
219	+
220	+  return { accepted, rejected, remaining };
221	+}
