226	+    const inputPath = parseInputFlag(argv);
227	+    input = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
228	+    validateFulfillWaveInput(input);
229	+  } catch (error) {
230	+    const message = error instanceof Error ? error.message : String(error);
231	+    process.stderr.write(`${JSON.stringify({ error: message })}\n`);
232	+    process.exit(2);
233	+  }
234	+
235	+  process.stdout.write(`${JSON.stringify(fulfillWave(input))}\n`);
236	+}
