diff --git a/bin/cli.js b/bin/cli.js
index 9cc9b24..6078ec7 100644
--- a/bin/cli.js
+++ b/bin/cli.js
@@ -35,6 +35,235 @@ function parseNameFlag(argv) {
   return value;
 }

+function ensure(condition, message) {
+  if (!condition) {
+    throw new Error(message);
+  }
+}
+
+function compareValues(left, right) {
+  if (left < right) return -1;
+  if (left > right) return 1;
+  return 0;
+}
+
+function isNonEmptyString(value) {
+  return typeof value === 'string' && value.length > 0;
+}
+
+function isPositiveInteger(value) {
+  return Number.isInteger(value) && value > 0;
+}
+
+function isValidDate(value) {
+  const parts = /^([0-9]{4})-([0-9]{2})-([0-9]{2})$/.exec(value);
+  if (!parts) return false;
+
+  const year = Number(parts[1]);
+  const month = Number(parts[2]);
+  const day = Number(parts[3]);
+  const date = new Date(Date.UTC(year, month - 1, day));
+
+  return date.getUTCFullYear() === year
+    && date.getUTCMonth() === month - 1
+    && date.getUTCDate() === day;
+}
+
+function submittedAtTimestamp(value) {
+  if (!isNonEmptyString(value)) return Number.NaN;
+
+  if (/^[+-]?[0-9]+(?:\.[0-9]+)?$/.test(value)) {
+    const timestamp = Number(value);
+    return Number.isFinite(timestamp) ? timestamp : Number.NaN;
+  }
+
+  return Date.parse(value);
+}
+
+function validateFulfillWaveInput(input) {
+  ensure(input !== null && typeof input === 'object' && !Array.isArray(input),
+    'input must be a JSON object');
+  ensure(Array.isArray(input.warehouses), 'warehouses must be an array');
+  ensure(Array.isArray(input.orders), 'orders must be an array');
+
+  for (const warehouse of input.warehouses) {
+    ensure(warehouse !== null && typeof warehouse === 'object' && !Array.isArray(warehouse),
+      'warehouse must be an object');
+    ensure(isNonEmptyString(warehouse.id), 'warehouse id must be a non-empty string');
+    ensure(typeof warehouse.distance === 'number' && Number.isFinite(warehouse.distance),
+      'warehouse distance must be a number');
+    ensure(Array.isArray(warehouse.lots), 'warehouse lots must be an array');
+
+    for (const lot of warehouse.lots) {
+      ensure(lot !== null && typeof lot === 'object' && !Array.isArray(lot),
+        'lot must be an object');
+      ensure(isNonEmptyString(lot.sku), 'lot sku must be a non-empty string');
+      ensure(isNonEmptyString(lot.lot), 'lot id must be a non-empty string');
+      ensure(isPositiveInteger(lot.qty), 'lot qty must be a positive integer');
+      ensure(isValidDate(lot.expires), 'lot expires must be a valid YYYY-MM-DD date');
+    }
+  }
+
+  const orderIds = new Set();
+  for (const order of input.orders) {
+    ensure(order !== null && typeof order === 'object' && !Array.isArray(order),
+      'order must be an object');
+    ensure(isNonEmptyString(order.id), 'order id must be a non-empty string');
+    ensure(!orderIds.has(order.id), 'order ids must be unique');
+    orderIds.add(order.id);
+    ensure(typeof order.priority === 'number' && Number.isFinite(order.priority),
+      'order priority must be a number');
+    ensure(Number.isFinite(submittedAtTimestamp(order.submitted_at)),
+      'order submitted_at must be an ISO date or timestamp');
+    ensure(Array.isArray(order.lines), 'order lines must be an array');
+
+    for (const line of order.lines) {
+      ensure(line !== null && typeof line === 'object' && !Array.isArray(line),
+        'order line must be an object');
+      ensure(isNonEmptyString(line.sku), 'order line sku must be a non-empty string');
+      ensure(isPositiveInteger(line.qty), 'order line qty must be a positive integer');
+      ensure(typeof line.single_warehouse === 'boolean',
+        'order line single_warehouse must be a boolean');
+    }
+  }
+}
+
+function parseInputFlag(argv) {
+  const index = argv.indexOf('--input');
+  const inputPath = argv[index + 1];
+  ensure(index !== -1 && isNonEmptyString(inputPath) && !inputPath.startsWith('-'),
+    '--input requires a path');
+  return inputPath;
+}
+
+function compareWarehouses(left, right) {
+  return compareValues(left.distance, right.distance)
+    || compareValues(left.id, right.id);
+}
+
+function compareLots(left, right) {
+  return compareValues(left.expires, right.expires)
+    || compareValues(left.lot, right.lot);
+}
+
+function buildWorkingStock(warehouses) {
+  return warehouses.map((warehouse) => ({
+    id: warehouse.id,
+    distance: warehouse.distance,
+    lots: warehouse.lots.map((lot) => ({
+      sku: lot.sku,
+      lot: lot.lot,
+      qty: lot.qty,
+      expires: lot.expires,
+    })).sort(compareLots),
+  })).sort(compareWarehouses);
+}
+
+function drawFromWarehouse(warehouse, sku, qty, allocations, deductions) {
+  let remaining = qty;
+
+  for (const lot of warehouse.lots) {
+    if (lot.sku !== sku || lot.qty === 0 || remaining === 0) continue;
+
+    const drawn = Math.min(lot.qty, remaining);
+    lot.qty -= drawn;
+    remaining -= drawn;
+    allocations.push({ sku, warehouse: warehouse.id, lot: lot.lot, qty: drawn });
+    deductions.push({ lot, qty: drawn });
+  }
+
+  return remaining;
+}
+
+function drawLine(stock, line, allocations, deductions) {
+  if (line.single_warehouse) {
+    for (const warehouse of stock) {
+      const available = warehouse.lots.reduce((total, lot) => (
+        lot.sku === line.sku ? total + lot.qty : total
+      ), 0);
+      if (available >= line.qty) {
+        return drawFromWarehouse(warehouse, line.sku, line.qty, allocations, deductions) === 0;
+      }
+    }
