    }
    return false;
  }

  let remaining = line.qty;
  for (const warehouse of stock) {
    remaining = drawFromWarehouse(warehouse, line.sku, remaining, allocations, deductions);
    if (remaining === 0) {
      return true;
    }
  }

  return false;
}

function fulfillWave(input) {
  const stock = buildWorkingStock(input.warehouses);
  const accepted = [];
  const rejectedIds = new Set();
  const orders = input.orders.map((order) => ({
    order,
    submittedAt: submittedAtTimestamp(order.submitted_at),
  })).sort((left, right) => (
    compareValues(right.order.priority, left.order.priority)
      || compareValues(left.submittedAt, right.submittedAt)
      || compareValues(left.order.id, right.order.id)
  ));

