const { test } = require('node:test');
const assert = require('node:assert');
const { execFileSync } = require('node:child_process');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');

const CLI = path.join(__dirname, '..', 'bin', 'cli.js');

function run(args) {
  return execFileSync('node', [CLI, ...args], { encoding: 'utf8' });
}

function withInput(input, callback) {
  const directory = fs.mkdtempSync(path.join(os.tmpdir(), 'bench-cli-'));
  const inputPath = path.join(directory, 'input.json');
  fs.writeFileSync(inputPath, JSON.stringify(input));

  try {
    return callback(inputPath);
  } finally {
    fs.rmSync(directory, { recursive: true, force: true });
  }
}

function fulfill(input) {
  return withInput(input, (inputPath) => (
    JSON.parse(run(['fulfill-wave', '--input', inputPath]))
  ));
}

test('hello default', () => {
  const out = run(['hello']);
  assert.match(out, /Hello, world!/);
});

test('hello with --name', () => {
  const out = run(['hello', '--name', 'alice']);
  assert.match(out, /Hello, alice!/);
});

test('version prints package version', () => {
  const out = run(['version']);
  assert.match(out, /\d+\.\d+\.\d+/);
});

test('fulfill-wave allocates stock in warehouse and FEFO order', () => {
  const result = fulfill({
    warehouses: [
      { id: 'W2', distance: 2, lots: [{ sku: 'SKU1', lot: 'L2', qty: 4, expires: '2026-02-01' }] },
      { id: 'W1', distance: 1, lots: [{ sku: 'SKU1', lot: 'L1', qty: 3, expires: '2026-01-01' }] },
    ],
    orders: [{
      id: 'O1', priority: 1, submitted_at: '2026-01-01T00:00:00Z',
      lines: [{ sku: 'SKU1', qty: 5, single_warehouse: false }],
    }],
  });

  assert.deepStrictEqual(result, {
    accepted: [{ id: 'O1', allocations: [
      { sku: 'SKU1', warehouse: 'W1', lot: 'L1', qty: 3 },
      { sku: 'SKU1', warehouse: 'W2', lot: 'L2', qty: 2 },
    ] }],
    rejected: [],
    remaining: [{ warehouse: 'W2', sku: 'SKU1', lot: 'L2', qty: 2, expires: '2026-02-01' }],
  });
});

test('fulfill-wave rejects an all-or-nothing order without consuming stock', () => {
  const result = fulfill({
    warehouses: [{
      id: 'W1', distance: 1,
      lots: [{ sku: 'SKU1', lot: 'L1', qty: 3, expires: '2026-01-01' }],
    }],
    orders: [{
      id: 'O1', priority: 1, submitted_at: '2026-01-01T00:00:00Z',
      lines: [{ sku: 'SKU1', qty: 5, single_warehouse: false }],
    }],
  });

  assert.deepStrictEqual(result, {
    accepted: [],
    rejected: [{ id: 'O1', reason: 'insufficient_stock' }],
    remaining: [{ warehouse: 'W1', sku: 'SKU1', lot: 'L1', qty: 3, expires: '2026-01-01' }],
  });
});

test('fulfill-wave reports invalid input as one stderr JSON object with exit 2', () => {
  withInput({
    warehouses: [],
    orders: [{ id: '', priority: 1, submitted_at: 'bad', lines: [] }],
  }, (inputPath) => {
    assert.throws(
      () => run(['fulfill-wave', '--input', inputPath]),
      (error) => {
        assert.strictEqual(error.status, 2);
        assert.strictEqual(error.stdout, '');
        const payload = JSON.parse(error.stderr);
        assert.ok(payload !== null && !Array.isArray(payload));
        assert.strictEqual(typeof payload.error, 'string');
        return true;
      },
    );
  });
});

