    remaining: [
      { warehouse: 'W1', sku: 'SKU1', lot: 'L1', qty: 3, expires: '2026-01-01' },
      { warehouse: 'W2', sku: 'SKU1', lot: 'L2', qty: 3, expires: '2026-01-01' },
